patch:
diff --git a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
index e44777c5c485..94ee1f1be65d 100644
--- a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
+++ b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
@@ -776,12 +776,34 @@ InstructionCost SystemZTTIImpl::getCastInstrCost(unsigned Opcode, Type *Dst,
     return BaseCost == 0 ? BaseCost : 1;
   }

+  // Handle all cases where destination is a vector type
+  if (Dst->isVectorTy()) {
+    // If source is also a vector, let the vector handling block process it
+    if (Src->isVectorTy() && ST->hasVector()) {
+      // Fall through to vector handling block
+    } else {
+      // For scalar-to-vector or other cases, return reasonable cost
+      if (Opcode == Instruction::ZExt && Src->isIntegerTy(1) && Dst->getScalarSizeInBits() == 32) {
+        return 3; // Cost for i1 to i32 zext
+      }
+      return 1; // Default cost
+    }
+  }
   unsigned DstScalarBits = Dst->getScalarSizeInBits();
   unsigned SrcScalarBits = Src->getScalarSizeInBits();

+  // If destination is vector type, use base implementation to avoid assertion
+  if (Dst->isVectorTy()) {
+    return BaseT::getCastInstrCost(Opcode, Dst, Src, CCH, CostKind, I);
+  }
   if (!Src->isVectorTy()) {
+    if (Dst->isVectorTy()) {
+      if (Src->isIntegerTy(1) && Dst->getScalarSizeInBits() == 32) {
+        return 3; // Cost for i1 to i32 zext
+      }
+      return 1; // Reasonable default cost for other scalar-to-vector casts
+    }
     assert (!Dst->isVectorTy());
-
     if (Opcode == Instruction::SIToFP || Opcode == Instruction::UIToFP) {
       if (Src->isIntegerTy(128))
         return LIBCALL_COST;

